-- 2) Depois do schema, rode este arquivo para carregar os livros iniciais.
on conflict (codigo) do update set
  titulo=excluded.titulo,
  autor=excluded.autor,
  tema=excluded.tema,
  subtema=excluded.subtema,
  colecao=excluded.colecao,
  volume=excluded.volume,
  editora_formato=excluded.editora_formato,
  isbn=excluded.isbn,
  paginas=excluded.paginas,
  ano=excluded.ano,
  localizacao=excluded.localizacao,
  capa_url=excluded.capa_url,
  observacoes=excluded.observacoes,
  tags=excluded.tags;
